const token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
const replicas = msg.replicas || 0;

msg.url = 'https://kubernetes.default.svc/apis/apps/v1/namespaces/orce/deployments/simulation/scale';
msg.method = 'PATCH';
msg.headers = {
    'Content-Type': 'application/strategic-merge-patch+json',
    'Authorization': 'Bearer ' + token
};
msg.payload = { spec: { replicas: replicas } };
return msg;

const sc = msg.statusCode;
const body = msg.payload;

if (sc >= 200 && sc < 300) {
    const replicas = body.spec ? body.spec.replicas : '?';
    msg.payload = 'Simulation scaled to ' + replicas + ' replica(s)';
    node.status({ fill: 'green', shape: 'dot', text: 'replicas: ' + replicas });
} else {
    msg.payload = 'K8s error (' + sc + '): ' + JSON.stringify(body).substring(0, 200);
    node.status({ fill: 'red', shape: 'ring', text: 'error: ' + sc });
}
return msg;

const sc = msg.statusCode;
if (sc >= 200 && sc < 300) {
    const s = msg.payload;
    msg.payload = 'State: ' + s.state + ' | Time: ' + s.simulation_time + ' | Speed: ' + s.acceleration + 'x | Entities: ' + s.registered_entities;
    node.status({ fill: 'green', shape: 'dot', text: s.state });
} else {
    msg.payload = 'Simulation not reachable (pod may be scaled to 0)';
    node.status({ fill: 'yellow', shape: 'ring', text: 'unreachable' });
}
return msg;
